var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"저기 보여, 엠마?! 출구야!","JPN":"エマ、あれが見える？　出口だよ！","ENG":"See that, Emma? It's an exit!","TWN":"愛瑪，你看？！是出口！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"꺄아악!?","JPN":"きゃああっ！","ENG":"Eeek!!","TWN":"啊～～！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"HERETIC_NPC_NULL_C","text":{"KOREA":"흐흐, 역시 주교님 말씀대로야. 출구만 확실히 장악하면 덜미가 잡힐 수밖에 없지.","JPN":"ふふ、やはり司教様の言うとおりだった。出口さえ確実に掌握しておけば問題ない。","ENG":"Hehe, it's just as the Bishop said… All we needed to do was secure the exit.","TWN":"嘿嘿，主教說的果然沒錯！只要守好出口一定能抓到人！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HERETIC_NPC_NULL_C","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HERETIC_NPC_NULL_D","face":"UNIT_LAUGH"}}}},{"id":"L11_1","type":"dialog","speaker":"HERETIC_NPC_NULL_D","text":{"KOREA":"한 명을 미끼로 삼아 나머지 둘이 탈출하려 했단 말이지.","JPN":"一人を囮にして二人で逃げようとしたようだな。","ENG":"So you tried to bait us with one of you so two of you could escape, eh?","TWN":"只要抓到一個，其他的自然也會上鉤！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HERETIC_NPC_NULL_C","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HERETIC_NPC_NULL_D","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"HERETIC_NPC_NULL_D","text":{"KOREA":"그런 잔머리로 대예언자 마젤란님의 적통을 이은 주교님의 혜안에서 벗어날 수 있을 줄 알았나?","JPN":"そんな小細工で大預言者マジェラン様の後継である司教様の慧眼から逃れられると思ったのか？","ENG":"Did you think a trick like that could deceive the wise Bishop, who carries on the legacy of Magellan?","TWN":"以為耍那種小手段，就可以逃出主教的五指山嗎？主教可是大預言家麥哲倫的繼承人呢！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HERETIC_NPC_NULL_C","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HERETIC_NPC_NULL_D","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"마젤란……? 당신들, 설마 그 뉴스에 나왔던 이상한 종교 집단이야?","JPN":"マジェラン……？　まさか、ニュースに出てたあの変なカルト集団？","ENG":"Magellan…? Hang on… Are you guys that weird cult that was on the news?","TWN":"麥哲倫……？難道你們就是新聞上說的邪教團體嗎？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HERETIC_NPC_NULL_C","text":{"KOREA":"닥쳐라! 언론의 혓바닥에 놀아나는 어리석은 자야!","JPN":"黙れ！　ゴミのようなマスコミに翻弄される愚か者め！","ENG":"Silence! The media's full of fake news, you gullible fool!","TWN":"閉嘴！你們這些受到輿論操控的笨蛋！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HERETIC_NPC_NULL_C","face":"UNIT_HATE"},"C":null,"R":{"char_id":"HERETIC_NPC_NULL_D","face":"UNIT_HATE"}}}},{"id":"L18_1","type":"dialog","speaker":"HERETIC_NPC_NULL_D","text":{"KOREA":"우리는 마젤란의 형제들! 신세계로 향하는 여정은 이 땅에서 다시 시작될지니!","JPN":"我々はマジェランの兄弟！　新世界へ向かう旅程は、この地で再び始まるのである！","ENG":"We're the brethren of Magellan, chosen by the Prophecy... The journey to the New World shall begin anew on this land!","TWN":"我們是麥哲倫的弟兄！前往新世界的旅程會從這裡重新出發！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HERETIC_NPC_NULL_C","face":"UNIT_HATE"},"C":null,"R":{"char_id":"HERETIC_NPC_NULL_D","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"신세계고 나발이고 알 바 아냐! 애가 죽어가는 거 안 보여?!","JPN":"新世界もくそも知ったこっちゃない！　この子の命が危ないんだよ！！","ENG":"I couldn't care less about your New World! Can't you see she's dying?!","TWN":"我管你什麼新世界還什麼鬼世界！沒看到她快死了嗎？！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"HERETIC_NPC_NULL_C","text":{"KOREA":"그래. 감히 우리의 성역에 기어들어와 새로운 엘릭서를 제조하는 현장을 엿봤기 때문이지.","JPN":"そうだ。聖域に潜り込み新しいエリクサーを製造する現場を覗き見た報いである。","ENG":"Oh, yes. It's because she dared to sneak into our sanctuary and spy on the new Elixir production.","TWN":"有看到，誰叫她擅闖我們的聖域，偷看我們製作新的聖水！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HERETIC_NPC_NULL_C","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HERETIC_NPC_NULL_D","face":"UNIT_LAUGH"}}}},{"id":"L24_1","type":"dialog","speaker":"HERETIC_NPC_NULL_D","text":{"KOREA":"죽음으로도 갚을 수 없는 중죄를 저지른 셈이다.","JPN":"そいつは死んでも償えない重罪を犯したのだ。","ENG":"Even death will not absolve her of this sin.","TWN":"這可是死也無法彌補的重罪！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HERETIC_NPC_NULL_C","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HERETIC_NPC_NULL_D","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"HERETIC_NPC_NULL_D","text":{"KOREA":"그리고 중죄인을 감싼 너도 예외는 아니지.","JPN":"そして重罪人をかばうお前も例外ではない。","ENG":"And you shall also meet retribution for protecting this sinner.","TWN":"而包庇罪人的你也無法倖免！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"HERETIC_NPC_NULL_D","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL_02"},{"id":"L28_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"큭…….","JPN":"くっ……","ENG":"Ugh…","TWN":"呃……"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HERETIC_NPC_NULL_D","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"꼬, 꼭 죽여서 해결할 필요는 없잖아! 이렇게나 예쁜 여자애가 어디 흔한 줄 알아?","JPN":"べ、別に殺して解決する必要はないでしょ？　アタシみたいに可愛い女の子なんて滅多にいないよ？","ENG":"K-killing isn't always the answer, you know! It's not every day you find a girl this pretty!","TWN":"有話好說，死…不能解決問題！你捨得殺掉這麼漂亮的女生嗎？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"HERETIC_NPC_NULL_D","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"원한다면 여자친구도 해 줄 수 있는데? 애인 없이 이런 곳에 처박혀 지내기도 따분하지?","JPN":"望むなら彼女になってあげてもいいよ？　みんな恋人もなく、こんな薄暗い所に引きこもって暮らすのもつまらないでしょ？","ENG":"I could be your girlfriend, if you'd like? Doesn't it get boring, being cooped up here without any romantic company?","TWN":"還是我幫你介紹女朋友？一個人孤伶伶地在這種地方生活很慘欸！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HERETIC_NPC_NULL_D","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"HERETIC_NPC_NULL_D","text":{"KOREA":"뭣……?","JPN":"なにっ……！","ENG":"What…?","TWN":"什麼……？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HERETIC_NPC_NULL_D","face":"UNIT_SURPRISE"}}}},{"id":"L33_1","type":"dialog","speaker":"HERETIC_NPC_NULL_C","text":{"KOREA":"저 계집애의 간악한 혓바닥에 흔들리지 마라!","JPN":"あの小娘の奸悪な舌先三寸に踊らされるな！","ENG":"Do not fall for that snake-tongued witch's temptation!","TWN":"不要因為那丫頭的話而動搖！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERETIC_NPC_NULL_C","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"HERETIC_NPC_NULL_C","text":{"KOREA":"주교님께서 계획만 성공하면 저런 애는 찌그러진 핫도그처럼 보일 미녀들을 소개해 준다고 하셨다!","JPN":"司教様が計画さえ成功すれば、あんなのはダンゴムシに見えるくらいの美女たちを紹介してくれるとおっしゃった！","ENG":"The Bishop promised he'd introduce us to beauties beyond compare once the plan is finished!","TWN":"主教說過，只要計畫成功，他就會介紹一堆看起來像如花的美女給我們！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERETIC_NPC_NULL_C","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"으아, 뉴스에서 나온 것보다 더 저질인 놈들이네…….","JPN":"うわぁ、ニュースの話よりも気色悪い連中だった……","ENG":"Eww, these guys are even creepier than I saw on the news…","TWN":"哇，這些傢伙的素質好像比新聞上說的還糟……"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HERETIC_NPC_NULL_D","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"HERETIC_NPC_NULL_D","text":{"KOREA":"하지만 그 여자들이랑 사귈 수 있다는 말씀은 안 하셨잖아.","JPN":"しかしその女たちと付き合えるという保証はないだろう。","ENG":"But he never said we'd get to go out with those ladies.","TWN":"但主教又沒說可以和那些女生交往！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HERETIC_NPC_NULL_D","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"HERETIC_NPC_NULL_D","text":{"KOREA":"신세계로 가기 전에 재미 좀 본다고 뭐라 하시겠어?","JPN":"新世界に行く前にちょっと遊んだって何も言われないだろうな？","ENG":"He won't mind if we have a little fun before we go to the New World, would he?","TWN":"在前往新世界前來點樂子，主教應該不會說什麼吧？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HERETIC_NPC_NULL_D","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"HERETIC_NPC_NULL_C","text":{"KOREA":"새, 생각해 보니 그런 것 같기도 하고…….","JPN":"そ、そう言われてみれば……","ENG":"N-now that you mention it, perhaps so…","TWN":"你這麼說，好像也有點道理……"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERETIC_NPC_NULL_C","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"HERETIC_NPC_NULL_C","text":{"KOREA":"좋다. 그렇다면 기회를 주지.","JPN":"いいだろう。チャンスを与えよう。","ENG":"Very well. We will give you a chance.","TWN":"好吧！那我就給你個機會！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERETIC_NPC_NULL_C","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"HERETIC_NPC_NULL_C","text":{"KOREA":"네 손으로 그 꼬마를 죽인다면 우리 마젤란의 형제들과 함께하게 해 주마.","JPN":"お前の手でその子を殺したら、マジェランの兄弟と一緒になることを許可してやる。","ENG":"If you kill the child yourself, we shall let you join the brethren.","TWN":"只要你親手殺掉那個小鬼，我就讓你和我們麥哲倫的弟兄在一起！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERETIC_NPC_NULL_C","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"자, 잠깐만! 그런 억지가 어디 있어!","JPN":"ま、待って！　それはおかしいよ！","ENG":"W-wait! That's not fair!","TWN":"歪腰，等等！這是什麼神展開？！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"HERETIC_NPC_NULL_C","text":{"KOREA":"그 말은 끝까지 중죄인을 감싸겠다는 뜻이군.","JPN":"つまり最後まで重罪人をかばうということだな。","ENG":"Then it sounds like you'll protect the sinner to the end.","TWN":"看來你是打算包庇罪人到底是吧？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HERETIC_NPC_NULL_C","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HERETIC_NPC_NULL_D","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"HERETIC_NPC_NULL_D","text":{"KOREA":"세 치 혀로 우릴 속이려 들어! 어리석은 여자 같으니!","JPN":"やはりその毒舌で我々を騙すつもりだったな！　この愚かなメス豚が！","ENG":"You dare try to fool us? Well, you're the fool for trying!","TWN":"竟然想用三寸不爛之舌唬爛我們！愚蠢的女人！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HERETIC_NPC_NULL_C","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HERETIC_NPC_NULL_D","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"HERETIC_NPC_NULL_C","text":{"KOREA":"저, 적이다! 어디서 쏜 거지!?","JPN":"て、敵だ！　どこから撃ってきた？","ENG":"E-enemies! Where are they firing from?!","TWN":"有…有敵人！槍手在哪裡？！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HERETIC_NPC_NULL_C","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HERETIC_NPC_NULL_D","face":"UNIT_HATE"}}}},{"id":"L6_1","type":"dialog","speaker":"HERETIC_NPC_NULL_D","text":{"KOREA":"빌어먹을, 적이고 뭐고 저 계집애만큼은 죽여야겠어!","JPN":"くそ、敵より先にあの女だけは殺さなければ！","ENG":"Damn it! Enemies or not, I'm going to kill that girl!","TWN":"該死的，管你什麼敵人，總之那女生必須死！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HERETIC_NPC_NULL_C","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HERETIC_NPC_NULL_D","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"HERETIC_NPC_NULL_C","text":{"KOREA":"죽기 싫으면 입 닥치고 후퇴해! 어서 후퇴!","JPN":"死にたくなければ黙って下がれ！　後退だ！","ENG":"Shut up and retreat if you want to live! Retreat!","TWN":"不想死的話就閉嘴閃開！快閃開！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HERETIC_NPC_NULL_C","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HERETIC_NPC_NULL_D","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"간발의 차였군. 늦지 않아서 다행이다.","JPN":"危ないところだったな。間に合ってよかった。","ENG":"That was close. Thank goodness we weren't too late.","TWN":"就差一點點！幸好有趕上！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L12_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"민우 아저씨?! 여긴 어떻게 알고 오셨어요?!","JPN":"マツダおじさん？　どうやってここに……！？","ENG":"Mr. Minwoo?! How did you know to find us here?!","TWN":"民宇叔叔？你怎麼知道我們在這裡？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"탐문 중에 주민들이 지하철에서 굉음이 들린다고 하길래 와 봤다. 운이 좋았어.","JPN":"聞き込み中に住民から地下鉄の方から轟音が聞こえると聞いてな。運が良かったな。","ENG":"While we were asking around, some folks said there was a loud noise from the subway. We got lucky.","TWN":"我們在打聽時，有人說聽到地鐵有奇怪的聲音，所以就過來看看。運氣真好！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"MEMBER_NPC_MILITIA_NULL","text":{"KOREA":"레이첼, 등에 업은 그 애 엠마 맞지? 많이 다친 것 같은데?","JPN":"レイチェル、背中の子はエマか？　傷が深そうだが。","ENG":"Rachel, that girl on your back. Is it Emma? She seems badly injured.","TWN":"瑞秋，你背上的是那個叫愛瑪的孩子對吧？她好像傷得很重？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEMBER_NPC_MILITIA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"맞아! 어서 진료소에 데려가라고 호라이즌이……!","JPN":"そうです！　はやく診療所に連れていけってホライズンが……！","ENG":"Oh, right! Horizon told us to go first to get her to the clinic…!","TWN":"對！要快點送她去診所，另外還有地平線她……！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"아차…… 저 인간들 때문에 까맣게 잊고 있었어.","JPN":"あちゃー！　あいつらのせいですっかり忘れてた！","ENG":"Oh no… I completely forgot about her because of those jerks.","TWN":"哎呀……被那些人搞到我都忘記了。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"호라이즌? 그 아이도 여기 온 건가?","JPN":"ホライズン？　あの子もここに来たのか？","ENG":"Horizon? That kid's here too?","TWN":"地平線？她也在這裡嗎？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"맞아요! 걔가 엠마를 쫓아오던 놈들을 유인한다고 사라졌어요!","JPN":"そうです！　エマを追いかけてきた奴らをおびき寄せるって一人で……！","ENG":"Yes! She disappeared to lure away those jerks who chased after Emma!","TWN":"對啊！她說要引開那些要抓愛瑪的人，然後就消失不見了！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"도와 주세요, 민우 아저씨! 앞으로 외상 달아 달라고 안 할게요, 네?","JPN":"助けてください、マツダおじさん！　もうツケとか言わないから！　お願い！","ENG":"Please help, Mr. Minwoo! I promise I'll pay for my stuff on time from now on. Please?","TWN":"民宇叔叔，你可以幫我找她嗎？我以後不會再說要賒帳了！好嗎？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"……산 넘어 산이로군.","JPN":"……一難去ってまた一難か。","ENG":"Out of the frying pan…","TWN":"……真是一波未平一波又起。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L24_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"알겠다. 너는 일단 저 애와 같이 진료소로 가 봐. 뒷일은 내가 알아서 하지.","JPN":"わかった。あんたはとりあえずあの子と一緒に診療所に行け。後のことは俺に任せろ。","ENG":"Fine. You go get the girl some medical help. I'll take care of the rest.","TWN":"好吧！你先和那個孩子到診所去，其他的我來處理。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":null,"text":{"KOREA":"그럴 필요없습니다. 휴먼.","JPN":"その必要はありません、ヒューマン。","ENG":"There's no need for that, human.","TWN":"不需要這麼做，人類。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L29_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"보시다시피 저는 멀쩡하니까요.","JPN":"見てのとおり、私は平気です。","ENG":"For as you can see, I am unharmed.","TWN":"如你所見，我沒事。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};